<template>
    <el-dialog
        v-model="visible"
        :title="title || $t('select-recipe')"
        width="800px"
        append-to-body
        @closed="handleClose"
    >
        <div class="search-bar">
            <el-input
                v-model="searchQuery"
                :placeholder="$t('search-item-placeholder')"
                @keyup.enter="handleSearch"
                clearable
            />
            <el-input-number
                v-if="showQuantityInput"
                v-model="quantity"
                :min="1"
                :step="1"
                :precision="0"
                :controls="false"
                class="quantity-input"
            />
            <el-button type="primary" @click="handleSearch" :loading="loading">{{ $t('search') }}</el-button>
        </div>

        <el-table
            :data="results"
            style="width: 100%; margin-top: 20px"
            height="400"
            v-tnze-loading="loading"
            @row-click="handleSelect"
            stripe
            highlight-current-row
        >
            <el-table-column prop="icon" width="60">
                <template #default="scope">
                    <!-- Placeholder for icon if available, or just use a generic one -->
                    <!-- We might need image URL logic later. For now, empty or generic -->
                    <el-icon><Goods /></el-icon>
                </template>
            </el-table-column>
            <el-table-column prop="name" :label="$t('item-name')" />
            <el-table-column prop="item_id" label="ID" width="100" v-if="mode !== 'item'" />
            <el-table-column prop="id" label="ID" width="100" v-else />
            
            <el-table-column prop="job" :label="$t('job')" width="100" v-if="mode !== 'item'">
                <template #default="scope">
                    {{ scope.row.job_code || scope.row.job_name || '-' }}
                </template>   
            </el-table-column>
             <el-table-column prop="rlv" :label="$t('level')" width="80" v-if="mode !== 'item'" />
             <el-table-column prop="level" :label="$t('level')" width="80" v-else />
        </el-table>

        <div class="pagination-container">
             <el-pagination
                v-if="results.length > 0"
                layout="prev, pager, next"
                :total="total"
                :page-size="pageSize"
                v-model:current-page="currentPage"
                @current-change="handlePageChange"
            />
        </div>
    </el-dialog>
</template>

<script setup lang="ts">
import { computed, ref, watch } from 'vue';
import { 
    ElDialog, 
    ElInput, 
    ElButton, 
    ElTable, 
    ElTableColumn, 
    ElIcon,
    ElPagination,
    ElMessage,
    ElInputNumber
} from 'element-plus';
import { Goods } from '@element-plus/icons-vue';
import { useFluent } from 'fluent-vue';
import useSettingsStore from '@/stores/settings';

const { $t } = useFluent();
const settingsStore = useSettingsStore();

interface ItemSelectorProps {
    modelValue: boolean;
    initialQuery?: string;
    title?: string;
    mode?: 'recipe' | 'item'; 
    allowQuantity?: boolean;
    customSearch?: (page: number, query: string) => Promise<{ results: any[], totalPages: number }>;
}

const props = defineProps<ItemSelectorProps>();

const emit = defineEmits<{
    (e: 'update:modelValue', value: boolean): void;
    (e: 'select', item: { id: number; name: string; recipeId: number; amount?: number }): void;
}>();

const visible = ref(false);
const searchQuery = ref('');
const loading = ref(false);
const results = ref<any[]>([]);
const total = ref(0);
const pageSize = 10;
const currentPage = ref(1);
const quantity = ref<number | undefined>(1);
const showQuantityInput = computed(() => props.mode === 'item' && props.allowQuantity);

// Sync modelValue with visible
watch(() => props.modelValue, (val) => {
    visible.value = val;
    if (val) {
        if (props.initialQuery && props.initialQuery !== searchQuery.value) {
            searchQuery.value = props.initialQuery;
            // Immediate search if we have an initial query
            handleSearch();
        } else {
             // If no initial query, maybe just load default/empty results?
             // User wants "sync", so maybe load page 1 immediately?
             if (!results.value.length) handleSearch();
        }
    }
});

watch(visible, (val) => {
    emit('update:modelValue', val);
});

// Live Search with Debounce
let debounceTimer: ReturnType<typeof setTimeout> | null = null;
watch(searchQuery, () => {
    if (debounceTimer) clearTimeout(debounceTimer);
    loading.value = true; // Show loading state early for feedback
    debounceTimer = setTimeout(() => {
        handleSearch();
    }, 500); // 500ms delay to avoid API spam
});

async function handleSearch() {
    // if (!searchQuery.value) return; // Allow empty search to show default/all items
    currentPage.value = 1;
    await fetchResults();
}

async function handlePageChange(page: number) {
    currentPage.value = page;
    await fetchResults();
}

async function fetchResults() {
    loading.value = true;
    try {
        if (props.customSearch) {
             const res = await props.customSearch(currentPage.value, searchQuery.value);
             results.value = res.results;
             // Ensure totalPages is valid number
             const pts = res.totalPages || 1;
             total.value = pts * 10;
        } else {
            const ds = await settingsStore.getDataSource();
            const res = await ds.recipeTable(currentPage.value, searchQuery.value);
            results.value = res.results.map(r => ({
                ...r,
                name: r.item_name, 
            }));
            const pts = res.totalPages || 1;
            total.value = pts * 10; 
        }
    } catch (e) {
        ElMessage.error($t('search-error') + ': ' + String(e));
    } finally {
        loading.value = false;
    }
}

function handleSelect(row: any) {
    if (props.mode === 'item') {
        // Row is Item: { id, name, ... }
        emit('select', {
            id: row.id,
            name: row.name,
            recipeId: 0,
            amount: Math.max(1, Number(quantity.value) || 1),
        });
    } else {
        // Row is Recipe: { id, item_id, item_name ... }
        emit('select', { id: row.item_id, name: row.name, recipeId: row.id });
    }
    visible.value = false;
}

function handleClose() {
    // Clear results?
    // results.value = [];
}
</script>

<style scoped>
.search-bar {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 10px;
    margin-bottom: 10px;
}
.search-bar > .el-input {
    width: 300px;
}
.quantity-input {
    width: 110px;
}
.pagination-container {
    display: flex;
    justify-content: center;
    margin-top: 15px;
}
</style>

